// Formata msg de resumo com DUAS seções:
// 1. SDR Zap (conversas pendentes) — já existia
// 2. Campanhas (enviados/respondidos/qualificados, chips, handoffs pendentes) — novo

// --- Seção SDR Zap ---
const sdrData = $('getResumo').item.json;
const { por_responsavel = [], total_respondidas_hoje = 0, total_aguardando = 0, gerado_em } = sdrData;
const dataFormatada = new Date(gerado_em || Date.now()).toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

let secoesSdr = '';
for (const resp of por_responsavel) {
  const items = (resp.pendentes || [])
    .sort((a, b) => b.tempo_minutos - a.tempo_minutos)
    .slice(0, 5)
    .map(p => {
      const emoji = p.urgencia === 'urgente' ? '🔴' : p.urgencia === 'atencao' ? '🟡' : '🟢';
      const tempo = p.tempo_minutos >= 60 ? Math.floor(p.tempo_minutos/60) + 'h' : p.tempo_minutos + 'min';
      return `  ${emoji} ${p.nome_contato} — ${tempo} sem resposta`;
    }).join('\n');
  secoesSdr += `\n👩‍💼 *${resp.nome}*: ${resp.total} pendente${resp.total !== 1 ? 's' : ''}\n${items}\n`;
}

const blocoSdr = total_aguardando === 0
  ? `✅ SDR Zap: todas conversas respondidas (${total_respondidas_hoje} hoje)`
  : `💬 *SDR ZAP*\n${secoesSdr}\n✅ Respondidas hoje: ${total_respondidas_hoje}\n⚠️ Aguardando: ${total_aguardando}`;

// --- Seção Campanhas ---
const campData = $json || {};
const { totais = {}, por_campanha = [], chips_pausados = [], handoffs_pendentes = [] } = campData;

let blocoCamp = '';
if ((totais.campanhas_ativas || 0) === 0) {
  blocoCamp = '\n\n📭 *CAMPANHAS*\nNenhuma campanha ativa.';
} else {
  let linhasCamp = '';
  for (const c of por_campanha) {
    linhasCamp += `\n• *${c.nome}*: ${c.enviados_hoje} enviadas, ${c.respondidos_hoje} responderam (${c.taxa_resposta_pct}%), ${c.qualificados_hoje} quentes`;
    if (c.descartados_hoje > 0) linhasCamp += `, ${c.descartados_hoje} descartadas`;
    if (c.falhas_hoje > 0) linhasCamp += `, ${c.falhas_hoje} falhas`;
  }
  if (!linhasCamp) linhasCamp = '\n(sem atividade hoje — disparo pausado ou aguardando ciclo)';

  blocoCamp = `\n\n📊 *CAMPANHAS* (${totais.campanhas_ativas} ativa${totais.campanhas_ativas > 1 ? 's' : ''})${linhasCamp}`;
  blocoCamp += `\n\n📈 Total hoje: ${totais.enviados_hoje} enviadas, ${totais.respondidos_hoje} respostas, ${totais.qualificados_hoje} quentes`;
  if (totais.em_conversa_agora > 0) blocoCamp += `\n💬 Em conversa agora: ${totais.em_conversa_agora}`;
}

// Chips pausados (alerta crítico)
if (chips_pausados.length > 0) {
  blocoCamp += `\n\n⚠️ *CHIPS PAUSADOS* (${chips_pausados.length}):`;
  for (const chip of chips_pausados.slice(0, 5)) {
    blocoCamp += `\n• ${chip.nome || 'sem nome'} ${chip.numero ? `(${chip.numero})` : ''}`;
  }
  blocoCamp += `\nAbra /zaps no CRM pra reconectar.`;
}

// Handoffs pendentes
if (handoffs_pendentes.length > 0) {
  blocoCamp += `\n\n🔥 *LEADS QUENTES AGUARDANDO* (${handoffs_pendentes.length}):`;
  for (const h of handoffs_pendentes.slice(0, 5)) {
    const quando = new Date(h.respondeu_em).toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo', hour: '2-digit', minute: '2-digit' });
    blocoCamp += `\n• ${h.telefone} (${h.campanha_nome}) — ${quando}`;
  }
}

const mensagem = `📊 *RESUMO DO DIA* — ${dataFormatada}\n\n${blocoSdr}${blocoCamp}`;

return [{ json: { mensagem } }];
